        if (seqNum == 0) return;

        CallRes memory cr = CallRes({
            reqId: reqId,
            rc: rc,
            lrc: lrc,
            count: count,
            blockNum: uint40(block.number),
            reserved: 0
        });

        // Track result via event (in tx receipt) and storage (easier to lookup by seqNum after storage lag)
